Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/PartyMakingTheApplicationList/PartyMakingTheApplication[./Value = " + PartyMakingTheApplication.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/PartyMakingTheApplicationList/PartyMakingTheApplication[./Description = " + PartyMakingTheApplication.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
